const data         = input.message;
const parts = (input.topic || '').split('/');
const code_machine = data.code_machine;
const type_mesure  = data.type_mesure;
const valeur       = parseFloat(data.valeur);
const unite        = data.unite    || '';
const esp32_id     = data.esp32_id || null;

if (data.valeur === undefined || data.valeur === null) {
  throw new Error('Payload invalide — valeur manquante : ' + code_machine + '/' + type_mesure);
}

return {
  code_machine,
  type_mesure,
  valeur:    parseFloat(data.valeur),
  unite:     data.unite    || '',
  esp32_id:  data.esp32_id || null,
  timestamp: new Date().toISOString()
};

const row = input.rows[0];
if (!row) throw new Error('Équipement ou capteur introuvable: {{outputs.Parse_Message.success.code_machine}}/{{outputs.Parse_Message.success.type_mesure}}');

const valeur   = {{outputs.Parse_Message.success.valeur}};
const seuilMin = parseFloat(row.seuil_min);
const seuilMax = parseFloat(row.seuil_max);

return {
  capteur_id:     row.capteur_id,
  equipement_id:  row.equipement_id,
  code_machine:   row.code_machine,
  nom_equipement: row.nom_equipement,
  criticite_gmp:  row.criticite_gmp,
  type_mesure:    '{{outputs.Parse_Message.success.type_mesure}}',
  valeur,
  unite:          row.unite,
  seuil_min:      seuilMin,
  seuil_max:      seuilMax,
  alerte_flag:    valeur == 300, //valeur < seuilMin || valeur > seuilMax,
  timestamp:      '{{outputs.Parse_Message.success.timestamp}}'
};

const mesures = input.rows || [];

// ── Webhook data : injecté champ par champ (syntaxe Fusion AI compatible) ──
const wh = {
    equipement_id:       '{{outputs.WF02_Webhook.success.body.equipement_id}}',
    capteur_id:          '{{outputs.WF02_Webhook.success.body.capteur_id}}',
    code_machine:        '{{outputs.WF02_Webhook.success.body.code_machine}}',
    nom_equipement:      '{{outputs.WF02_Webhook.success.body.nom_equipement}}',
    criticite_gmp:       '{{outputs.WF02_Webhook.success.body.criticite_gmp}}',
    type_mesure:         '{{outputs.WF02_Webhook.success.body.type_mesure}}',
    valeur:              parseFloat('{{outputs.WF02_Webhook.success.body.valeur}}') || 0,
    unite:               '{{outputs.WF02_Webhook.success.body.unite}}',
    seuil_min:           parseFloat('{{outputs.WF02_Webhook.success.body.seuil_min}}') || 0,
    seuil_max:           parseFloat('{{outputs.WF02_Webhook.success.body.seuil_max}}') || 0,
    timestamp:           '{{outputs.WF02_Webhook.success.body.timestamp}}'
};

// ── Helper : parse un timestamp PostgreSQL "2026-04-29 20:44:17.072+00" ──
function safeDate(ts) {
    if (!ts) return null;
    const iso = String(ts).replace(' ', 'T');
    const d = new Date(iso);
    return isNaN(d.getTime()) ? null : d;
}

// ── Extraction des valeurs ──
const valeurs = mesures
    .map(m => parseFloat(m.valeur))
    .filter(v => !isNaN(v));

const nb_alertes = mesures.filter(m => m.alerte_flag === true).length;

// ── Delta (valeur finale - valeur initiale) ──
let delta = 0;
if (valeurs.length >= 2) {
    delta = parseFloat((valeurs[valeurs.length - 1] - valeurs[0]).toFixed(2));
}

// ── Durée en minutes ──
let duree_min = 0;
if (mesures.length >= 2) {
    const t0 = safeDate(mesures[0].timestamp);
    const t1 = safeDate(mesures[mesures.length - 1].timestamp);
    if (t0 && t1) {
        duree_min = (t1 - t0) / 60000;
    }
}

// ── Classification tendance ──
let tendance = 'ponctuel';
if (Math.abs(delta) > 5 && duree_min > 0) {
    tendance = delta > 0 ? 'hausse_rapide' : 'chute_rapide';
} else if (nb_alertes >= 3) {
    tendance = 'persistant';
}

// ── Return ──
return {
    equipement_id:       wh.equipement_id,
    capteur_id:          wh.capteur_id,
    code_machine:        wh.code_machine,
    nom_equipement:      wh.nom_equipement,
    criticite_gmp_equip: wh.criticite_gmp,
    type_mesure:         wh.type_mesure,
    valeur:              wh.valeur,
    unite:               wh.unite || '',
    seuil_min:           wh.seuil_min,
    seuil_max:           wh.seuil_max,
    timestamp:           wh.timestamp,
    tendance,
    delta,
    nb_alertes,
    nb_mesures:          valeurs.length
};

