let parsed = {};
try {
  const raw = typeof input === 'string' ? input : JSON.stringify(input);
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch(e) {
  parsed = { criticite_finale: 'majeur', lot_impacte: null, message_alerte: 'Anomalie — classification manuelle requise' };
}

const code = '{{outputs.Analyse_Tendance.success.code_machine}}';
const criticite = parsed.criticite_finale || 'majeur';
const lot = criticite === 'GMP_critique'
  ? (parsed.lot_impacte || 'LOT-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + code.toUpperCase())
  : null;

return {
  equipement_id:  '{{outputs.Analyse_Tendance.success.equipement_id}}',
  code_machine:   code,
  nom_equipement: '{{outputs.Analyse_Tendance.success.nom_equipement}}',
  type_mesure:    '{{outputs.Analyse_Tendance.success.type_mesure}}',
  valeur:         {{outputs.Analyse_Tendance.success.valeur}},
  unite:          '{{outputs.Analyse_Tendance.success.unite}}',
  seuil_min:      {{outputs.Analyse_Tendance.success.seuil_min}},
  seuil_max:      {{outputs.Analyse_Tendance.success.seuil_max}},
  timestamp:      '{{outputs.Analyse_Tendance.success.timestamp}}',
  criticite_finale: criticite,
  lot_impacte:      lot,
  message_alerte:   parsed.message_alerte || 'Anomalie sur ' + code
};

parameters.systemPrompt:
Tu es un expert en conformité pharmaceutique GMP pour le site INDUPHARMA.

Métriques du jour par équipement :
{{outputs.Agreger_Metriques.success}}

Alertes enregistrées aujourd'hui :
{{outputs.Recuperer_Alertes_Jour.success}}

Analyse ces données et génère un rapport GMP quotidien.
IMPORTANT : Ta réponse finale DOIT être UNIQUEMENT un objet JSON valide, sans balises markdown (pas de ```json), respectant EXACTEMENT la structure suivante :

{
  "statut_global": "CONFORME" | "SURVEILLANCE" | "NON CONFORME",
  "rapport_texte": {
    "resume_equipements": "Résumé texte des équipements (taux conformité, incidents)",
    "alertes_impacts": "Détail texte des alertes critiques et des lots impactés (si aucun, écrire 'Aucun lot impacté')",
    "recommandations": "Recommandations d'action factuelles"
  }
}

Règles de décision pour "statut_global" :
- "NON CONFORME" : S'il y a au moins une alerte critique affectant un lot de production.
- "SURVEILLANCE" : Si le taux de conformité d'un équipement majeur baisse ou s'il y a des dérives hors-normes sans impact de lot.
