parameters.code:
const rapport_texte = typeof input === 'string' ? input : JSON.stringify(input);
const date_rapport  = new Date().toISOString().slice(0, 10);
const statut = rapport_texte.includes('NON CONFORME') ? 'NON CONFORME'
             : rapport_texte.includes('SURVEILLANCE') ? 'SURVEILLANCE'
             : 'CONFORME';

return {
  date_rapport,
  statut_global: statut,
  rapport_texte,
  sujet_email: '[Rapport GMP ' + date_rapport + '] ' + statut + ' — INDUPHARMA'
};

const rows = input.rows || [];

const equipements = rows.map(e => {
  let mesures = [];
  if (typeof e.mesures_recentes === 'string') {
    try {
      mesures = JSON.parse(e.mesures_recentes);
    } catch {
      mesures = [];
    }
  } else {
    mesures = e.mesures_recentes || [];
  }

  let rootCauses = [];
  if (typeof e.root_causes === 'string') {
    try {
      rootCauses = JSON.parse(e.root_causes);
    } catch {
      rootCauses = [];
    }
  } else if (Array.isArray(e.root_causes)) {
    rootCauses = e.root_causes;
  }
  rootCauses = rootCauses.filter(rc => rc !== null && rc !== undefined && rc !== '');

  const techniciens = Array.isArray(e.techniciens)
    ? e.techniciens.map(t => ({
        name: t.name,
        role: t.role,
        email: t.email,
        phone: t.phone,
        is_available:
          typeof t.is_available === 'boolean'
            ? t.is_available
            : String(t.is_available).toLowerCase() === 'true',
        action_taken: t.action_taken,
        started_at: t.started_at,
        completed_at: t.completed_at,
        status: t.completed_at ? 'done' : 'in_progress'
      }))
    : [];

  return {
    equipement_id:       e.equipement_id,
    code_machine:        e.code_machine,
    nom:                 e.nom,
    zone_production:     e.zone_production,
    type_equipement:     e.type_equipement,
    criticite_gmp:       e.criticite_gmp,
    statut:              e.statut,
    nb_alertes_ouvertes: parseInt(e.nb_alertes_ouvertes || 0),

    etat_global: parseInt(e.nb_alertes_ouvertes || 0) > 0
      ? 'alerte'
      : 'ok',

    root_causes: rootCauses,

    mesures_recentes: mesures,

    techniciens,

    techniciens_count: techniciens.length,
    techniciens_active: techniciens.filter(t => t.status === 'in_progress').length
  };
});

const nb_alertes_total   = equipements.reduce((s, e) => s + e.nb_alertes_ouvertes, 0);
const equipements_alerte = equipements.filter(e => e.etat_global === 'alerte').length;
const techniciens_total  = equipements.reduce((s, e) => s + e.techniciens_count, 0);

return {
  meta: JSON.stringify({
    generated_at: new Date().toISOString(),
    nb_equipements: equipements.length,
    equipements_ok: equipements.length - equipements_alerte,
    equipements_alerte,
    nb_alertes_total,
    techniciens_total
  }),

  data: JSON.stringify(equipements)
};
